  ('bookkeeper-moex-01197', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據民國 104 年新修正之行政程序法，授予利益之行政處分，其內容係提供一次或連續之金錢或可分物 之給付者，經撤銷、廢止或條件成就而有溯及既往失效之情形時，下列敘述何者錯誤？', '["受益人應返還因該處分所受領之給付", "受益人應返還範圍準用民法有關不當得利之規定", "行政機關依規定請求返還時，應以書面行政處分確認返還範圍，並限期命受益人返還之", "行政機關作成請求返還之行政處分時，應同時移送行政執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
